class RateLimiter:
    """Token-bucket style rate limiter with sliding window counters."""

    def __init__(self):
        self._lock = Lock()
        # key -> list of timestamps
        self._requests: dict[str, list[float]] = defaultdict(list)
        # Track consecutive failed searches per IP for anti-enumeration
        self._failed_searches: dict[str, list[float]] = defaultdict(list)
        # Blocked IPs with expiry
        self._blocked: dict[str, float] = {}

    def _cleanup(self, bucket: list[float], window: float) -> list[float]:
        now = time.time()
        return [t for t in bucket if now - t < window]

    def is_blocked(self, key: str) -> bool:
        with self._lock:
            if key in self._blocked:
                if time.time() < self._blocked[key]:
                    return True
                else:
                    del self._blocked[key]
            return False

    def block(self, key: str, duration: float):
        with self._lock:
            self._blocked[key] = time.time() + duration

    def is_rate_limited(self, key: str, max_requests: int, window: float) -> bool:
        """Return True if the key has exceeded max_requests in the window (seconds)."""
        with self._lock:
            now = time.time()
            self._requests[key] = self._cleanup(self._requests[key], window)
            if len(self._requests[key]) >= max_requests:
                return True
            self._requests[key].append(now)
            return False

    def record_failed_search(self, key: str):
        """Track failed/empty searches for anti-enumeration."""
        with self._lock:
            now = time.time()
            window = 60.0  # 1-minute window
            self._failed_searches[key] = self._cleanup(
                self._failed_searches[key], window
            )
            self._failed_searches[key].append(now)

    def get_failed_search_count(self, key: str, window: float = 60.0) -> int:
        with self._lock:
            self._failed_searches[key] = self._cleanup(
                self._failed_searches[key], window
            )
            return len(self._failed_searches[key])


rate_limiter = RateLimiter()


def get_client_identifier() -> str:
    """Derive a stable identifier for the client (IP + optional API key)."""
    ip = request.headers.get('X-Forwarded-For', request.remote_addr)
    if ip and ',' in ip:
        ip = ip.split(',')[0].strip()
    api_key = request.headers.get('X-API-Key', '')
    raw = f"{ip}:{api_key}"
    return hashlib.sha256(raw.encode()).hexdigest()[:32]


def get_client_ip() -> str:
    ip = request.headers.get('X-Forwarded-For', request.remote_addr)
    if ip and ',' in ip:
        ip = ip.split(',')[0].strip()
    return ip or 'unknown'


def rate_limit(max_requests: int = 60, window: float = 60.0,
               block_threshold: int = 200, block_duration: float = 300.0):
    """
    Decorator that applies rate limiting.

    Args:
        max_requests: Maximum requests allowed in the window.
        window: Time window in seconds.
        block_threshold: If exceeded by this factor, temporarily block.
        block_duration: How long to block in seconds.
    """
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_id = get_client_identifier()
            client_ip = get_client_ip()

            # Check if IP is temporarily blocked
            if rate_limiter.is_blocked(client_id):
                logger.warning(
                    "Blocked request from %s (temp ban)", client_ip
                )
                return jsonify({
                    'error': 'Too many requests. You have been temporarily blocked.',
                    'retry_after': int(block_duration)
                }), 429

            if rate_limiter.is_rate_limited(client_id, max_requests, window):
                logger.warning(
                    "Rate limited request from %s", client_ip
                )
                # If they keep hammering, escalate to a temporary block
                if rate_limiter.is_rate_limited(
                    f"block_check:{client_id}", block_threshold, window
                ):
                    rate_limiter.block(client_id, block_duration)
                    logger.warning(
                        "Temporarily blocking %s for %ss", client_ip, block_duration
                    )

                response = jsonify({
                    'error': 'Rate limit exceeded. Please slow down.',
                    'retry_after': int(window)
                })
                response.status_code = 429
                response.headers['Retry-After'] = str(int(window))
                return response

            g.client_id = client_id
            g.client_ip = client_ip
            return f(*args, **kwargs)
        return wrapped
    return decorator


def anti_enumeration(max_empty_results: int = 20, window: float = 60.0,
                     block_duration: float = 120.0):
    """
    Decorator to detect and block enumeration attempts.
    If a client makes too many searches that return zero results,
    they are likely probing/enumerating.
    """
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            response = f(*args, **kwargs)

            # Only check on successful responses
            if isinstance(response, tuple):
                resp_obj, status_code = response[0], response[1]
            else:
                resp_obj, status_code = response, 200

            if status_code == 200:
                try:
                    data = resp_obj.get_json()
                    total = data.get('total', 0)
                    if total == 0:
                        client_id = getattr(g, 'client_id', get_client_identifier())
                        client_ip = getattr(g, 'client_ip', get_client_ip())
                        rate_limiter.record_failed_search(client_id)
                        failed_count = rate_limiter.get_failed_search_count(
                            client_id, window
                        )
                        if failed_count >= max_empty_results:
                            logger.warning(
                                "Anti-enumeration: blocking %s after %d empty searches",
                                client_ip, failed_count
                            )
                            rate_limiter.block(client_id, block_duration)
                            return jsonify({
                                'error': 'Suspicious activity detected. Temporarily blocked.',
                                'retry_after': int(block_duration)
                            }), 429
                except Exception:
                    pass

            return response
        return wrapped
    return decorator


