def sanitize_search_query(query: str) -> str:
    """Sanitize search query to prevent Elasticsearch injection."""
    if not query:
        return ''
    # Remove Elasticsearch special characters that could be used for injection
    special_chars = [
        '\\', '+', '-', '!', '(', ')', ':', '^', '[', ']',
        '"', '{', '}', '~', '*', '?', '|', '&', '/', '<', '>'
    ]
    sanitized = query
    for char in special_chars:
        sanitized = sanitized.replace(char, ' ')
    # Collapse multiple spaces
    sanitized = ' '.join(sanitized.split())
    return sanitized.strip()


def validate_pagination(page: int, size: int) -> tuple[int, int]:
    """Validate and constrain pagination parameters."""
    page = max(1, min(page, 100))  # Max 100 pages deep
    size = max(1, min(size, 50))   # Max 50 results per page
    return page, size


