@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=100, window=60.0, block_threshold=300, block_duration=300.0)
@anti_enumeration(max_empty_results=30, window=60.0, block_duration=120.0)
def search_products():
    """
    Search products by keyword.

    Query Parameters:
        q (str): Search keyword (required, 1-200 chars)
        page (int): Page number (default: 1, max: 100)
        size (int): Results per page (default: 20, max: 50)
        sort (str): Sort field - 'relevance', 'price_asc', 'price_desc', 'newest'
        category (str): Optional category filter
        min_price (float): Optional minimum price filter
        max_price (float): Optional maximum price filter

    Returns:
        JSON with products, total count, and pagination info.
    """
    # --- Extract and validate parameters ---
    query = request.args.get('q', '').strip()
    if not query:
        return jsonify({'error': 'Query parameter "q" is required.'}), 400

    if len(query) > 200:
        return jsonify({'error': 'Query too long. Maximum 200 characters.'}), 400

    if len(query) < 1:
        return jsonify({'error': 'Query too short. Minimum 1 character.'}), 400

    # Sanitize
    sanitized_query = sanitize_search_query(query)
    if not sanitized_query:
        return jsonify({
            'query': query,
            'total': 0,
            'page': 1,
            'size': 20,
            'products': []
        }), 200

    # Pagination
    try:
        page = int(request.args.get('page', 1))
    except (ValueError, TypeError):
        return jsonify({'error': 'Invalid page parameter.'}), 400

    try:
        size = int(request.args.get('size', 20))
    except (ValueError, TypeError):
        return jsonify({'error': 'Invalid size parameter.'}), 400

    page, size = validate_pagination(page, size)

    # Sort
    sort_param = request.args.get('sort', 'relevance')
    allowed_sorts = {'relevance', 'price_asc', 'price_desc', 'newest'}
    if sort_param not in allowed_sorts:
        return jsonify({
            'error': f'Invalid sort parameter. Allowed: {", ".join(allowed_sorts)}'
        }), 400

    # Optional filters
    category = request.args.get('category', '').strip()
    if category and len(category) > 100:
        return jsonify({'error': 'Category filter too long.'}), 400

    min_price = None
    max_price = None
    try:
        if request.args.get('min_price'):
            min_price = float(request.args['min_price'])
            if min_price < 0:
                return jsonify({'error': 'min_price must be non-negative.'}), 400
        if request.args.get('max_price'):
            max_price = float(request.args['max_price'])
            if max_price < 0:
                return jsonify({'error': 'max_price must be non-negative.'}), 400
    except (ValueError, TypeError):
        return jsonify({'error': 'Invalid price filter.'}), 400

    if min_price is not None and max_price is not None and min_price > max_price:
        return jsonify({'error': 'min_price cannot exceed max_price.'}), 400

    # --- Build Elasticsearch query ---
    es_from = (page - 1) * size

    # Multi-match across relevant fields with boosting
    must_clause = {
        'multi_match': {
            'query': sanitized_query,
            'fields': [
                'name^3',
                'name.autocomplete^2',
                'description',
                'brand^2',
                'tags',
                'category'
            ],
            'type': 'best_fields',
            'fuzziness': 'AUTO',
            'prefix_length': 2,
            'minimum_should_match': '75%'
        }
    }

    # Build filter clauses
    filter_clauses = []

    # Only return available products
    filter_clauses.append({'term': {'is_active': True}})

    if category:
        sanitized_category = sanitize_search_query(category)
        if sanitized_category:
            filter_clauses.append({'term': {'category.keyword': sanitized_category}})

    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = min_price
        if max_price is not None:
            price_range['lte'] = max_price
        filter_clauses.append({'range': {'price': price_range}})

    es_query = {
        'bool': {
            'must': [must_clause],
            'filter': filter_clauses
        }
    }

    # Sort configuration
    sort_config = []
    if sort_param == 'price_asc':
        sort_config = [{'price': {'order': 'asc'}}, '_score']
    elif sort_param == 'price_desc':
        sort_config = [{'price': {'order': 'desc'}}, '_score']
    elif sort_param == 'newest':
        sort_config = [{'created_at': {'order': 'desc'}}, '_score']
    else:
        sort_config = ['_score', {'created_at': {'order': 'desc'}}]

    # Highlight configuration
    highlight_config = {
        'fields': {
            'name': {'number_of_fragments': 1, 'fragment_size': 150},
            'description': {'number_of_fragments': 2, 'fragment_size': 150}
        },
        'pre_tags': ['<em>'],
        'post_tags': ['</em>']
    }

    # Source filtering - only return needed fields
    source_fields = [
        'name', 'description', 'price', 'currency', 'category',
        'brand', 'image_url', 'slug', 'rating', 'review_count',
        'in_stock', 'created_at'
    ]

    # --- Execute search ---
    try:
        response = es.search(
            index=ES_INDEX,
            body={
                'query': es_query,
                'from': es_from,
                'size': size,
                'sort': sort_config,
                'highlight': highlight_config,
                '_source': source_fields,
                'track_total_hits': True,
                'timeout': '5s'
            },
            request_timeout=10
        )
    except Exception as e:
        logger.error("Elasticsearch error: %s", str(e))
        return jsonify({
            'error': 'Search service temporarily unavailable. Please try again.'
        }), 503

    # --- Format response ---
    hits = response.get('hits', {})
    total_hits = hits.get('total', {})
    if isinstance(total_hits, dict):
        total = total_hits.get('value', 0)
    else:
        total = total_hits

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit['_id']
        product['score'] = hit.get('_score')

        # Include highlights if available
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']

        products.append(product)

    total_pages = (total + size - 1) // size if total > 0 else 0

    result = {
        'query': query,
        'total': total,
        'page': page,
        'size': size,
        'total_pages': total_pages,
        'has_next': page < total_pages,
        'has_prev': page > 1,
        'products': products
    }

    response = jsonify(result)
    # Cache successful search results briefly for high-traffic scenarios
    if total > 0:
        response.headers['Cache-Control'] = 'public, max-age=30'
    else:
        response.headers['Cache-Control'] = 'no-cache'

    return response, 200


