@app.route('/api/health', methods=['GET'])
@rate_limit(max_requests=10, window=60.0)
def health_check():
    """Health check endpoint."""
    try:
        es_healthy = es.ping()
    except Exception:
        es_healthy = False

    status = 'healthy' if es_healthy else 'degraded'
    status_code = 200 if es_healthy else 503

    return jsonify({
        'status': status,
        'elasticsearch': 'connected' if es_healthy else 'disconnected'
    }), status_code


