@app.before_request
def log_request():
    g.start_time = time.time()


@app.after_request
def log_response(response):
    if hasattr(g, 'start_time'):
        duration = time.time() - g.start_time
        client_ip = getattr(g, 'client_ip', get_client_ip())
        logger.info(
            "%s %s %s %d %.3fs",
            client_ip,
            request.method,
            request.path,
            response.status_code,
            duration
        )
    return response


